{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires identifying a mistake in a derivation of stack-based bracket matching. Since the specific derivation steps are not provided in the prompt, the helpers are tasked with establishing the ground truth logic and then verifying the specific sequence provided in the user's context.",
  "helpers": [
    {
      "label": "logic_verifier",
      "instructions": "Define the formal rules for a stack-based bracket matching algorithm. Specify the exact state of the stack after each character is processed for a given sequence of (), [], {}, and <>. List the expected stack contents step-by-step for a sample sequence to serve as a gold standard."
    },
    {
      "label": "derivation_auditor",
      "instructions": "Compare the provided derivation steps in the question against the formal rules of stack-based matching. Identify the specific step number or character index where the stack state, the bracket being popped, or the error type (mismatch vs. empty stack vs. leftover elements) deviates from the correct algorithmic execution."
    }
  ],
  "synthesis_brief": "The parent agent will take the formal rules and gold standard from the logic_verifier and use them to validate the auditor's findings. The final answer will be the specific index or step identified by the auditor as the first point of failure."
}

